class Booking:
    secret_key = "CONFIRM123"  # This is a class variable representing the secret key for all Booking instances.

    def __init__(self, booking_id, passengers, flight):
        self.booking_id = booking_id
        self.passengers = passengers
        self.flight = flight
        self.__confirmationstatus = False
        self.__paymentdetails = None

    def __getconfirmationstatus(self):
        return self.__confirmationstatus

    def confirm(self, secret_key, payment_details):
        if secret_key == Booking.secret_key:
            self.__confirmationstatus = True
            self.__paymentdetails = payment_details
            print("Booking confirmed.")
        else:
            print("Invalid secret key.")

    def checkin(self):
        if self.__getconfirmationstatus():
            print("Check-in complete.")
        else:
            print("Please confirm your booking first.")

def default_test():
    booking = Booking(booking_id=123, passengers=2, flight="LX197")
    print("Booking ID:", booking.booking_id)
    print("Passengers:", booking.passengers)
    print("Flight:", booking.flight)
